package main

import (
	"math"
)

// solve finds the smallest stable index i.
func solve(nums []int64, k int64) int64 {
	n := len(nums)
	if n == 0 {
		// Should not happen based on constraints (N >= 1), but good practice.
		return -1
	}

	// 1. Calculate Prefix Maximums (LMax)
	lMax := make([]int64, n)
	currentMax := nums[0]
	lMax[0] = currentMax
	for i := 1; i < n; i++ {
		if nums[i] > currentMax {
			currentMax = nums[i]
		}
		lMax[i] = currentMax
	}

	// 2. Calculate Suffix Minimums (RMin)
	rMin := make([]int64, n)
	currentMin := nums[n-1]
	rMin[n-1] = currentMin
	for i := n - 2; i >= 0; i-- {
		if nums[i] < currentMin {
			currentMin = nums[i]
		}
		rMin[i] = currentMin
	}

	// 3. Check for the smallest stable index
	for i := 0; i < n; i++ {
		// Instability Value = LMax[i] - RMin[i]
		instabilityValue := lMax[i] - rMin[i]

		if instabilityValue <= k {
			// Found the smallest stable index
			return int64(i)
		}
	}

	// If no stable index is found
	return -1
}
